sql:
SELECT interaction_id, ROUND(avg_gain, 2) AS rounded_avg_gain, ROUND(avg_wfscore, 2) AS rounded_avg_wfscore
FROM interactions
ORDER BY avg_gain DESC, avg_wfscore DESC;

external_knowledge:
- 'Older than 18' refers to adults; 
- 'Moderate level' of effectiveness is assumed to be an average weighted FScore greater than 0.5; 
- 'Specific context' refers to a particular setting or situation in which the interactions occur.
